            type="text"
            value={registerData.name}
            onChange={(e) => setRegisterData({ ...registerData, name: e.target.value })}
            required
          />
        </div>
        <div>
          <label>Email:</label>
          <input
            type="email"
            value={registerData.email}
            onChange={(e) => setRegisterData({ ...registerData, email: e.target.value })}
            required
          />
        </div>
        <div>
          <label>Password:</label>
          <input
            type="password"
            value={registerData.password}
            onChange={(e) => setRegisterData({ ...registerData, password: e.target.value })}
            required
          />
        </div>
        <button type="submit" disabled={loading}>
          {loading ? 'Registering...' : 'Register'}
        </button>
        <p style={{ marginTop: '15px', textAlign: 'center' }}>
          Already have an account? <button onClick={() => setCurrentView('login')} style={{ background: 'none', border: 'none', color: '#ff9800', cursor: 'pointer' }}>Login here</button>
        </p>
      </form>
    </div>
  );

  return (
    <div>
      {renderNav()}
      {currentView === 'home' && renderHome()}
      {currentView === 'about' && renderAbout()}
      {currentView === 'contact' && renderContact()}
      {currentView === 'profile' && renderProfile()}
      {currentView === 'admin' && user?.role === 'admin' && renderAdminPanel()}
      {currentView === 'login' && !user && renderLogin()}
      {currentView === 'register' && !user && renderRegister()}

      <footer>
        <p>© 2024 Hot Wheels Blog | Passion for Collecting | All Rights Reserved</p>
      </footer>
    </div>
  );
}

export default App;
